// Descoberta de ofertas no Mercado Livre, em duas etapas por keyword:
// 1) página de listagem/busca (lista.mercadolivre.com.br/{keyword}) com User-Agent de bot de
//    preview do WhatsApp — devolve um JSON-LD @graph com vários produtos de uma vez (nome,
//    imagem, preço atual, link), validado em 2026-07-13.
// 2) pra cada candidato da listagem, busca a página individual do produto (mesmo UA, já validado
//    no projeto price-monitor-n8n) só pra pegar o preço ORIGINAL — a listagem não traz isso, mas
//    a página de produto tem um elemento com aria-label="Antes: X reais" quando há desconto ativo.
// MAX_CANDIDATES_PER_KEYWORD limita quantas páginas de produto buscamos por keyword, pra manter
// o volume de requisições razoável rodando a cada 30 min.
const WA_UA = 'WhatsApp/2.23.20.0 A';
const MAX_CANDIDATES_PER_KEYWORD = 15;
const MIN_DISCOUNT_PCT = 20;

const categories = $input.all().map(item => item.json.keyword);
const results = [];

for (const keyword of categories) {
  let listingHtml;
  try {
    listingHtml = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://lista.mercadolivre.com.br/${encodeURIComponent(keyword)}`,
      headers: { 'User-Agent': WA_UA },
    });
  } catch (e) {
    continue; // keyword falhou (rede/bloqueio) — segue pra próxima, não trava a rodada inteira
  }

  const ldMatches = [...listingHtml.matchAll(/<script[^>]*application\/ld\+json[^>]*>(.*?)<\/script>/gs)];
  let products = [];
  for (const m of ldMatches) {
    try {
      const data = JSON.parse(m[1]);
      if (data['@graph']) {
        products = data['@graph'].filter(x => x['@type'] === 'Product');
        break;
      }
    } catch (e) {
      // bloco JSON-LD inválido/inesperado — ignora e tenta o próximo
    }
  }

  const candidates = products.slice(0, MAX_CANDIDATES_PER_KEYWORD);

  for (const p of candidates) {
    const url = p.offers && p.offers.url;
    const currentPrice = p.offers && p.offers.price;
    if (!url || !currentPrice) continue;

    const idMatch = url.match(/MLB\d+/);
    const productId = idMatch ? idMatch[0] : url;

    let detailHtml;
    try {
      detailHtml = await this.helpers.httpRequest({
        method: 'GET',
        url,
        headers: { 'User-Agent': WA_UA },
      });
    } catch (e) {
      continue;
    }

    const beforeMatch = detailHtml.match(/aria-label="Antes:\s*(\d+)(?:\s*reais(?:\s*com\s*(\d+)\s*centavos)?)?"/);
    if (!beforeMatch) continue; // sem desconto ativo agora

    const originalPrice = parseFloat(beforeMatch[1]) + (beforeMatch[2] ? parseFloat(beforeMatch[2]) / 100 : 0);
    if (!(originalPrice > currentPrice)) continue;

    const discountPct = ((originalPrice - currentPrice) / originalPrice) * 100;
    if (discountPct < MIN_DISCOUNT_PCT) continue;

    results.push({
      json: {
        platform: 'ml',
        product_id: productId,
        product_url: url,
        product_name: p.name || '',
        image_url: p.image || '',
        current_price: currentPrice,
        original_price: originalPrice,
        discount_pct: Math.round(discountPct * 10) / 10,
      },
    });
  }
}

return results;
